function splitSidebarLabel(label = '') {
  const normalized = String(label || '').trim()
  const match = normalized.match(/^(\S+)\s+(.*)$/)
  if (!match) return { icon: '•', text: normalized }
  return { icon: match[1], text: match[2] }
}

