function formatAppErrorMessage(rawMessage) {
  const message = String(rawMessage || '')

  if (message.includes('FREE_LIMIT') || message.includes('FREE_TIP_LIMIT_REACHED')) {
    return 'Masz maksymalny limit 5 typów dziennie na koncie FREE. Przejdź na Premium, aby dodawać bez limitu.'
  }

  if (message.includes('PREMIUM_REQUIRED') || message.includes('Tylko konta Premium')) {
    return 'Baza nadal widzi konto jako FREE. Uruchom BETAI_SQL_910_FIX_FREE_TIPS_NOT_PREMIUM.sql, wyloguj się i zaloguj ponownie.'
  }

  if (message.includes('new row violates row-level security') || message.includes('row-level security')) {
    return 'Brak uprawnień do zapisu. Zaloguj się ponownie i spróbuj jeszcze raz.'
  }

  if (message.includes('duplicate key')) {
    return 'Ten rekord już istnieje w bazie.'
  }

  return message.replace(/^Error:\s*/i, '').replace(/\s*\|\s*Supabase:.*/i, '').trim() || 'Wystąpił błąd. Spróbuj ponownie.'
}

function getTipErrorToast(cleanMessage) {
  if (cleanMessage.includes('5 typów dziennie') || cleanMessage.includes('FREE')) {
    return {
      type: 'limit',
      title: 'Limit konta FREE',
      message: 'Masz maksymalny limit 5 typów dziennie. Premium odblokowuje dodawanie bez limitu.',
      cta: 'Przejdź na Premium',
      event: 'betai:start-premium-checkout'
    }
  }

  if (cleanMessage.includes('Premium') || cleanMessage.includes('premium')) {
    return {
      type: 'premium',
      title: 'Wymagane konto Premium',
      message: 'Nie posiadasz konta Premium. Aktywuj Premium, aby dodawać typy premium.',
      cta: 'Aktywuj Premium',
      event: 'betai:start-premium-checkout'
    }
  }

  return { type: 'error', title: 'Nie dodano typu', message: cleanMessage }
}

function AnimatedDashboardHero() {
  const heroSlides = [
    { src: '/dashboard-hero-v551/slide-1.png', alt: 'Bet+AI platforma — typy, analiza i społeczność' },
    { src: '/dashboard-hero-v551/slide-2.png', alt: 'Bet+AI marketplace — kupuj i sprzedawaj typy oraz analizy' },
    { src: '/dashboard-hero-v551/slide-3.png', alt: 'Bet+AI rewards — coiny, dropy, typy i nagrody' },
    { src: '/dashboard-hero-v551/slide-4.png', alt: 'Bet+AI community — społeczność typerów i live chat' },
    { src: '/dashboard-hero-v551/slide-5.png', alt: 'Bet+AI platform — AI analizuje mecze za Ciebie' },
    { src: '/dashboard-hero-v551/slide-6.png', alt: 'Bet+AI media — artykuły, newsy, PPV i wyniki live' }
  ]
  const [panel, setPanel] = useState(0)
  const [isHeroPaused, setIsHeroPaused] = useState(false)
  const heroSwipeStart = useRef(null)

  useEffect(() => {
    if (isHeroPaused || heroSlides.length <= 1) return undefined
    const panelTimer = window.setInterval(() => setPanel(prev => (prev + 1) % heroSlides.length), 6000)
    return () => window.clearInterval(panelTimer)
  }, [heroSlides.length, isHeroPaused])

  const moveHeroSlide = (direction) => setPanel(prev => (prev + direction + heroSlides.length) % heroSlides.length)
  const handleHeroPointerUp = (event) => {
    const startX = heroSwipeStart.current
    heroSwipeStart.current = null
    if (startX == null) return
    const diff = event.clientX - startX
    if (Math.abs(diff) > 40) moveHeroSlide(diff < 0 ? 1 : -1)
  }

  return (
    <section
      className="betai-dashboard-hero-v551"
      aria-label="Nowy hero dashboardu Bet+AI"
      onMouseEnter={() => setIsHeroPaused(true)}
      onMouseLeave={() => setIsHeroPaused(false)}
      onPointerDown={(event) => { heroSwipeStart.current = event.clientX }}
      onPointerUp={handleHeroPointerUp}
    >
      <div className="betai-dashboard-stage-v551" aria-hidden="true">
        {heroSlides.map((slide, index) => (
          <div key={slide.src} className={`betai-dashboard-slide-v551 ${panel === index ? 'active' : ''}`}>
            <img src={slide.src} alt="" draggable="false" />
          </div>
        ))}
      </div>


      <div className="betai-dashboard-nav-v551">
        <button type="button" className="hero-arrow-v553 hero-arrow-left-v553" aria-label="Poprzedni slajd" onClick={() => moveHeroSlide(-1)}>‹</button>
        <button type="button" className="hero-arrow-v553 hero-arrow-right-v553" aria-label="Następny slajd" onClick={() => moveHeroSlide(1)}>›</button>
      </div>
    </section>
  )
}

const BETAI_CHAT_PROFANITY_WORDS = [
  'kurwa', 'kurwo', 'kurwy', 'kurwie', 'kurew', 'kurewski', 'kurewska', 'kurwiarz',
  'chuj', 'chuja', 'chuje', 'chujem', 'chujowy', 'chujowa', 'huj', 'huja', 'huje',
  'pierdol', 'pierdolę', 'pierdole', 'pierdolony', 'pierdolona', 'spierdalaj', 'wypierdalaj', 'zapierdala',
  'jebac', 'jebać', 'jebie', 'jebany', 'jebana', 'zjeb', 'zjeba', 'pojeb', 'pojebany', 'pojebana',
  'pizda', 'pizdo', 'pizdy', 'pizde', 'pizdę', 'pizdzie',
  'suka', 'suko', 'suki', 'sukinsyn', 'skurwysyn', 'skurwiel', 'skurw',
  'dupa', 'dupek', 'dupku', 'dupka',
  'cwel', 'cwela', 'cwele', 'cwelu',
  'idiota', 'idiotka', 'debil', 'debilu', 'debile', 'kretyn', 'kretynie'
]

function escapeBetaiRegex(value = '') {
  return String(value).replace(/[.*+?^${}()|[\]\\]/g, '\\$&')
}

const BETAI_CHAT_PROFANITY_RE = new RegExp('(^|[^a-zA-Z0-9ąćęłńóśźżĄĆĘŁŃÓŚŹŻ])(' + BETAI_CHAT_PROFANITY_WORDS.map(escapeBetaiRegex).join('|') + ')(?=$|[^a-zA-Z0-9ąćęłńóśźżĄĆĘŁŃÓŚŹŻ])', 'giu')

function betaiContainsProfanity(value = '') {
  BETAI_CHAT_PROFANITY_RE.lastIndex = 0
  return BETAI_CHAT_PROFANITY_RE.test(String(value || ''))
}

function betaiCensorChatText(value = '') {
  BETAI_CHAT_PROFANITY_RE.lastIndex = 0
  return String(value || '').replace(BETAI_CHAT_PROFANITY_RE, (full, prefix, word) => `${prefix}${'•'.repeat(Math.max(3, String(word || '').length))}`)
}

function betaiParseChatBlockError(error) {
  const raw = String(error?.message || error?.details || error || '')
  const match = raw.match(/CHAT_BLOCKED_UNTIL:([^|\s]+)/i)
  if (!match) return ''
  const until = new Date(match[1])
  if (Number.isNaN(until.getTime())) return 'Masz czasową blokadę czatu za przekleństwa.'
  return `Masz blokadę czatu do ${until.toLocaleString('pl-PL')} za przekleństwa.`
}

function LiveChatPanel({ user }) {
  const [messages, setMessages] = useState([])
  const [text, setText] = useState('')
  const [status, setStatus] = useState('🎁 Tip na czacie = max 1 nagroda / 24h')
  const [sending, setSending] = useState(false)
  const [onlineCount, setOnlineCount] = useState(1)
  const [tippingId, setTippingId] = useState('')
  const [showEmojiPicker, setShowEmojiPicker] = useState(false)

  const email = normalizeEmail(user?.email)
  const userName = resolveRealProfileUsername(user) || (email ? email.split('@')[0] : 'Użytkownik')
  const currentAvatarUrl = getProfileAvatarUrl(user)

  const nameFromEmail = (value = '') => {
    const clean = normalizeEmail(value)
    if (!clean) return 'Gość'
    if (clean === 'smilhytv@gmail.com') return 'Smilhytv'
    return clean.split('@')[0].replace(/[._-]+/g, ' ').split(' ').filter(Boolean).map(part => part.charAt(0).toUpperCase() + part.slice(1)).join(' ')
  }

  const initialsFromName = (name = '') => {
    const clean = String(name || 'LC').trim()
    const parts = clean.split(/\s+/).filter(Boolean)
    if (parts.length >= 2) return parts.slice(0, 2).map(part => part.charAt(0)).join('').slice(0, 2).toUpperCase() || 'LC'
    return clean.replace(/[^a-zA-Z0-9ąćęłńóśźżĄĆĘŁŃÓŚŹŻ]/g, '').slice(0, 2).toUpperCase() || 'LC'
  }

  const todayKey = () => new Date().toISOString().slice(0, 10)

  const safeInsertSystemNotification = async (recipientEmail, title, body, rewardTokens = 0) => {
    const recipient = normalizeEmail(recipientEmail)
    if (!recipient || !isSupabaseConfigured || !supabase) return
    try {
      await supabase.from('betai_system_notifications').insert({
        recipient_email: recipient,
        title,
        body,
        reward_tokens: Number(rewardTokens || 0) || 0,
        sent_by: 'betai',
        is_read: false
      })
    } catch (error) {
      console.warn('chat notification skipped', error)
    }
  }

  const getTokenWallet = async (walletEmail, fallbackUserId = null) => {
    const walletKey = normalizeEmail(walletEmail)
    if (!walletKey || !isSupabaseConfigured || !supabase) return { email: walletKey, balance: 0, user_id: fallbackUserId }
    try {
      const { data, error } = await supabase
        .from('betai_token_wallets')
        .select('*')
        .eq('email', walletKey)
        .maybeSingle()
      if (!error && data) return { ...data, balance: Number(data.balance || 0) || 0 }
    } catch (error) {
      console.warn('chat get wallet skipped', error)
    }
    try {
      const localBalance = Number(localStorage.getItem('betai_tokens_' + walletKey) || '0') || 0
      return { email: walletKey, balance: localBalance, user_id: fallbackUserId }
    } catch (_) {
      return { email: walletKey, balance: 0, user_id: fallbackUserId }
    }
  }

  const setTokenWallet = async (walletEmail, nextBalance, fallbackUserId = null) => {
    const walletKey = normalizeEmail(walletEmail)
    const cleanBalance = Math.max(0, Number(nextBalance || 0) || 0)
    if (!walletKey) return cleanBalance
    try { localStorage.setItem('betai_tokens_' + walletKey, String(cleanBalance)) } catch (_) {}
    if (!isSupabaseConfigured || !supabase) return cleanBalance
    try {
      await supabase.from('betai_token_wallets').upsert({
        email: walletKey,
        user_id: fallbackUserId || null,
        balance: cleanBalance,
        welcome_bonus_claimed: true,
        updated_at: new Date().toISOString()
      }, { onConflict: 'email' })
    } catch (error) {
      console.warn('chat set wallet skipped', error)
    }
    return cleanBalance
  }

  const addTokenTransaction = async (walletEmail, deltaTokens, reason, refType = 'live_chat', refData = null) => {
    const walletKey = normalizeEmail(walletEmail)
    if (!walletKey || !isSupabaseConfigured || !supabase) return
    try {
      await supabase.from('betai_token_transactions').insert({
        email: walletKey,
        delta_tokens: Number(deltaTokens || 0) || 0,
        delta_pln: 0,
        reason,
        ref_type: refType,
        ref_data: refData || null
      })
    } catch (error) {
      console.warn('chat token tx skipped', error)
    }
  }

  const awardDailyLeaderIfNeeded = async (currentMessages = messages) => {
    if (!isSupabaseConfigured || !supabase) return
    const start = new Date(); start.setHours(0, 0, 0, 0)
    const activity = new Map()
    ;(currentMessages || []).forEach(m => {
      const ts = new Date(m.created_at).getTime()
      const key = normalizeEmail(m.user_email)
      if (key && ts >= start.getTime()) activity.set(key, { email: key, count: (activity.get(key)?.count || 0) + 1, name: m.user_name || nameFromEmail(key), user_id: m.user_id || null })
    })
    const dailyLeader = [...activity.values()].sort((a, b) => b.count - a.count)[0]
    if (!dailyLeader?.email || dailyLeader.count < 1) return
    const rewardDate = todayKey()
    try {
      const { data: existing } = await supabase.from('live_chat_daily_rewards').select('reward_date,winner_email').eq('reward_date', rewardDate).maybeSingle()
      if (existing?.reward_date) return
      const { error } = await supabase.from('live_chat_daily_rewards').insert({
        reward_date: rewardDate,
        winner_email: dailyLeader.email,
        winner_name: dailyLeader.name,
        message_count: dailyLeader.count,
        tokens_awarded: 1
      })
      if (error) return
      const wallet = await getTokenWallet(dailyLeader.email, dailyLeader.user_id)
      await setTokenWallet(dailyLeader.email, Number(wallet.balance || 0) + 1, wallet.user_id || dailyLeader.user_id || null)
      await addTokenTransaction(dailyLeader.email, 1, 'live_chat_daily_leader', 'live_chat_daily_rewards', { reward_date: rewardDate, message_count: dailyLeader.count })
      await safeInsertSystemNotification(dailyLeader.email, 'Nagroda za aktywność na czacie', `Gratulacje! Jesteś liderem aktywności BetAI Live Chat za dziś. Dodaliśmy 1 coin do Twojego konta.`, 1)
      setStatus(`🏆 ${dailyLeader.name} dostał 1 coin za top aktywność 24h.`)
    } catch (error) {
      console.warn('daily chat reward skipped', error)
    }
  }

  const loadOnlineCount = async () => {
    if (!email || !isSupabaseConfigured || !supabase) {
      setOnlineCount(email ? 1 : 0)
      return
    }
    const now = new Date().toISOString()
    try {
      await supabase.from('presence_heartbeats').upsert({
        user_id: user?.id || email,
        email,
        last_seen: now
      }, { onConflict: 'user_id' })
    } catch (error) {
      console.warn('chat heartbeat skipped', error)
    }
    try {
      const cutoff = new Date(Date.now() - 60 * 1000).toISOString()
      const { data, error } = await supabase
        .from('presence_heartbeats')
        .select('user_id,email,last_seen')
        .gte('last_seen', cutoff)
      if (error) throw error
      const active = new Set((data || []).map(row => normalizeEmail(row.email) || String(row.user_id || '')).filter(Boolean))
      setOnlineCount(active.size)
    } catch (error) {
      console.warn('chat online count skipped', error)
      setOnlineCount(email ? 1 : 0)
    }
  }

  const loadMessages = async () => {
    if (!isSupabaseConfigured || !supabase) {
      setStatus('Live chat: Supabase nie jest skonfigurowany')
      return
    }
    try {
      const { data, error } = await supabase
        .from('live_chat_messages')
        .select('id,user_email,user_name,avatar_url,message,tipped_amount,created_at')
        .order('created_at', { ascending: false })
        .limit(20)
      if (error) throw error
      let nextMessages = (data || []).reverse()

      // WERSJA 912: avatar w czacie zawsze z prawdziwego profilu/cache.
      // Nie ufamy starym avatar_url z wiadomości, bo mogły zostać zapisane od innego użytkownika.
      cacheBetaiCurrentUserAvatar(user)
      try {
        const chatProfileMap = new Map()
        const addProfileAvatar = (profile = {}) => {
          const avatar = getProfileAvatarUrl(profile)
          if (!avatar) return
          const emailKey = normalizeEmail(profile.email || profile.user_email || profile.author_email)
          const nameKey = normalizeEmail(profile.username || profile.user_name || profile.author_name)
          const localKey = emailKey ? normalizeEmail(emailKey.split('@')[0]) : ''
          if (profile.id) chatProfileMap.set(String(profile.id).toLowerCase(), avatar)
          if (emailKey) chatProfileMap.set(emailKey, avatar)
          if (localKey) chatProfileMap.set(localKey, avatar)
          if (nameKey) chatProfileMap.set(nameKey, avatar)
        }

        // Najpierw RPC publicznych profili — to jest źródło prawdy niezależnie od zalogowanego konta.
        try {
          const chatProfiles = await fetchBetaiPublicProfiles()
          ;(chatProfiles || []).forEach(addProfileAvatar)
        } catch (profileAvatarError) {
          console.warn('chat profiles avatar hydration skipped', profileAvatarError)
        }

        // Fallback tylko wtedy, kiedy nie ma profilu w mapie.
        try {
          const { data: chatTipAuthors } = await supabase
            .from('tips').select('*')
            .order('created_at', { ascending: false })
            .limit(150)
          ;(chatTipAuthors || []).forEach(row => {
            const emailKey = normalizeEmail(row.author_email)
            const nameKey = normalizeEmail(row.author_name || row.username)
            const localKey = emailKey ? normalizeEmail(emailKey.split('@')[0]) : ''
            const avatar = row.author_avatar_url || row.profile_avatar_url || row.avatar_url || ''
            if (!avatar) return
            if (emailKey && !chatProfileMap.has(emailKey)) chatProfileMap.set(emailKey, avatar)
            if (localKey && !chatProfileMap.has(localKey)) chatProfileMap.set(localKey, avatar)
            if (nameKey && !chatProfileMap.has(nameKey)) chatProfileMap.set(nameKey, avatar)
          })
        } catch (tipAvatarError) {
          console.warn('chat tip avatar fallback skipped', tipAvatarError)
        }

        nextMessages = nextMessages.map(row => {
          const emailKey = normalizeEmail(row.user_email)
          const nameKey = normalizeEmail(row.user_name)
          const localKey = emailKey ? normalizeEmail(emailKey.split('@')[0]) : ''
          let mappedAvatar = chatProfileMap.get(emailKey) || chatProfileMap.get(localKey) || chatProfileMap.get(nameKey) || ''
          const currentAvatar = getProfileAvatarUrl(user)
          const currentEmail = normalizeEmail(user?.email)
          const currentName = normalizeEmail(user?.username || user?.user_metadata?.username || user?.user_metadata?.name)
          if (currentAvatar && ((currentEmail && emailKey === currentEmail) || (currentName && nameKey === currentName))) mappedAvatar = currentAvatar
          // mappedAvatar ma pierwszeństwo nad row.avatar_url, bo row.avatar_url bywa błędny/stary.
          return mappedAvatar ? { ...row, avatar_url: mappedAvatar } : row
        })
      } catch (avatarError) {
        console.warn('chat avatar hydration skipped', avatarError)
      }

      setMessages(nextMessages)
      setStatus('Live chat połączony — wiadomości odświeżają się automatycznie.')
      // Wersja 606: lider czatu jest nagradzany funkcją SQL o 00:00, nie podczas odświeżania UI.
    } catch (error) {
      console.error('live chat load error', error)
      setStatus('Live chat: reconnect z Supabase...')
    }
  }

  useEffect(() => {
    loadMessages()
    if (!isSupabaseConfigured || !supabase) return undefined
    const channel = supabase
      .channel('betai-live-chat-226-react')
      .on('postgres_changes', { event: '*', schema: 'public', table: 'live_chat_messages' }, loadMessages)
      .subscribe((nextStatus) => {
        if (nextStatus === 'SUBSCRIBED') setStatus('Live chat połączony — wiadomości odświeżają się automatycznie.')
        if (['CHANNEL_ERROR', 'TIMED_OUT', 'CLOSED'].includes(nextStatus)) setStatus('Realtime chwilowo niedostępny — włączone odświeżanie.')
      })
    const timer = setInterval(loadMessages, BETAI_REFRESH_INTERVALS.liveChatFallbackMs)
    return () => {
      clearInterval(timer)
      supabase.removeChannel(channel)
    }
  }, [])

  useEffect(() => {
    const host = document.querySelector('.betai-chat-messages-final')
    if (host) host.scrollTop = host.scrollHeight
  }, [messages.length])

  useEffect(() => {
    loadOnlineCount()
    const timer = setInterval(loadOnlineCount, BETAI_REFRESH_INTERVALS.onlineCountMs)
    window.addEventListener('focus', loadOnlineCount)
    return () => {
      clearInterval(timer)
      window.removeEventListener('focus', loadOnlineCount)
    }
  }, [email, user?.id])

  const todayCount = useMemo(() => {
    const start = new Date(); start.setHours(0, 0, 0, 0)
    return messages.filter(m => new Date(m.created_at).getTime() >= start.getTime()).length
  }, [messages])

  const leader = useMemo(() => {
    const start = new Date(); start.setHours(0, 0, 0, 0)
    const map = new Map()
    messages.forEach(m => {
      const ts = new Date(m.created_at).getTime()
      const key = normalizeEmail(m.user_email)
      if (key && ts >= start.getTime()) map.set(key, { email: key, count: (map.get(key)?.count || 0) + 1, name: m.user_name || nameFromEmail(key) })
    })
    return [...map.values()].sort((a, b) => b.count - a.count)[0] || null
  }, [messages])

  const sendMessage = async () => {
    const clean = String(text || '').trim().slice(0, 240)
    const hadProfanity = betaiContainsProfanity(clean)
    if (!clean || sending) return
    if (!email) {
      setStatus('Musisz być zalogowany, aby pisać na live chacie.')
      return
    }
    if (!isSupabaseConfigured || !supabase) {
      setStatus('Live chat: Supabase nie jest skonfigurowany')
      return
    }
    setSending(true)
    try {
      const { error } = await supabase.from('live_chat_messages').insert({
        user_email: email,
        user_name: userName,
        avatar_url: currentAvatarUrl || '',
        message: clean,
        tipped_amount: 0,
        created_at: new Date().toISOString()
      })
      if (error) throw error

      try {
        const { data: bonusResult, error: bonusError } = await supabase.rpc('award_live_chat_first_message_bonus_v606', {
          p_email: email,
          p_user_id: user?.id || null,
          p_user_name: userName
        })
        if (!bonusError && bonusResult?.awarded) {
          window.dispatchEvent(new CustomEvent('betai-token-balance-changed'))
          setStatus(`Wiadomość wysłana. Bonus dzienny: +${Number(bonusResult.tokens_awarded || 1)} coin za pierwszą wiadomość dnia.`)
        } else {
          setStatus(hadProfanity ? 'Wiadomość wysłana, ale przekleństwa zostały wykropkowane. Ostrzeżenie dodane do powiadomień.' : 'Wiadomość wysłana na live chat.')
        }
      } catch (bonusError) {
        console.warn('daily chat message bonus skipped', bonusError)
        setStatus(hadProfanity ? 'Wiadomość wysłana, ale przekleństwa zostały wykropkowane. Ostrzeżenie dodane do powiadomień.' : 'Wiadomość wysłana na live chat.')
      }

      setText('')
      await loadMessages()
    } catch (error) {
      console.error('live chat send error', error)
      const blockMessage = betaiParseChatBlockError(error)
      setStatus(blockMessage || 'Nie udało się wysłać wiadomości online. Sprawdź Supabase i spróbuj ponownie.')
    } finally {
      setSending(false)
    }
  }

  const sendTip = async (msg) => {
    if (!msg?.id || tippingId) return
    const targetEmail = normalizeEmail(msg.user_email)
    if (!email) {
      setStatus('Musisz być zalogowany, aby wysłać tip.')
      return
    }
    if (!targetEmail) {
      setStatus('Nie znaleziono konta odbiorcy tipa.')
      return
    }
    if (email === targetEmail) {
      setStatus('Nie możesz tipować samego siebie.')
      return
    }
    if (!isSupabaseConfigured || !supabase) {
      setStatus('Tipy wymagają połączenia z Supabase.')
      return
    }

    setTippingId(String(msg.id))
    try {
      const senderWallet = await getTokenWallet(email, user?.id || null)
      if (Number(senderWallet.balance || 0) < 1) {
        setStatus('Masz za mało coinów, aby wysłać tip.')
        return
      }

      const receiverWallet = await getTokenWallet(targetEmail, null)
      let receiverUserId = receiverWallet.user_id || null
      try {
        const { data: receiverProfile } = await supabase
          .from('profiles').select('*')
          .eq('email', targetEmail)
          .maybeSingle()
        receiverUserId = receiverProfile?.id || receiverUserId
      } catch (lookupError) {
        console.warn('tip receiver profile lookup skipped', lookupError)
      }
      const nextSenderBalance = Number(senderWallet.balance || 0) - 1
      const nextReceiverBalance = Number(receiverWallet.balance || 0) + 1
      await setTokenWallet(email, nextSenderBalance, senderWallet.user_id || user?.id || null)
      await setTokenWallet(targetEmail, nextReceiverBalance, receiverWallet.user_id || null)

      const nextAmount = Number(msg.tipped_amount || 0) + 1
      await supabase.from('live_chat_messages').update({ tipped_amount: nextAmount }).eq('id', msg.id)
      await supabase.from('live_chat_tips').insert({
        message_id: String(msg.id),
        from_email: email,
        to_email: targetEmail,
        amount: 1
      })

      // WERSJA 681: zapis TIP popupu z fallbackiem pod stare schematy bazy.
      // Wysyłamy także sender_email / receiver_email, żeby popup działał nawet gdy receiver_id jest pusty.
      const tipTransferPayload = {
        sender_id: user?.id || senderWallet.user_id || null,
        receiver_id: receiverUserId,
        sender_username: userName || email.split('@')[0] || 'Użytkownik',
        receiver_username: msg.user_name || nameFromEmail(targetEmail),
        sender_email: email,
        receiver_email: targetEmail,
        amount: 1
      }
      {
        const { error: tipTransferError } = await supabase.from('tip_transfers').insert(tipTransferPayload)
        if (tipTransferError) {
          const message = String(tipTransferError?.message || tipTransferError || '')
          const maybeLegacySchema = /sender_email|receiver_email|column|schema cache/i.test(message)
          if (!maybeLegacySchema) throw tipTransferError
          const { error: legacyTipTransferError } = await supabase.from('tip_transfers').insert({
            sender_id: tipTransferPayload.sender_id,
            receiver_id: tipTransferPayload.receiver_id,
            sender_username: tipTransferPayload.sender_username,
            receiver_username: tipTransferPayload.receiver_username,
            amount: tipTransferPayload.amount
          })
          if (legacyTipTransferError) throw legacyTipTransferError
        }
      }
      await addTokenTransaction(email, -1, 'live_chat_tip_sent', 'live_chat_tips', { message_id: String(msg.id), to_email: targetEmail })
      await addTokenTransaction(targetEmail, 1, 'live_chat_tip_received', 'live_chat_tips', { message_id: String(msg.id), from_email: email })
      await safeInsertSystemNotification(targetEmail, 'Dostałeś tip na czacie', `${userName} wysłał Ci 1 coin za wiadomość na BetAI Live Chat.`, 1)
      await safeInsertSystemNotification(email, 'Tip wysłany', `Wysłałeś 1 coin do ${msg.user_name || nameFromEmail(targetEmail)}.`, 0)

      window.dispatchEvent(new CustomEvent('betai-token-balance-changed'))
      setStatus(`Tip wysłany do ${msg.user_name || nameFromEmail(targetEmail)}. Twoje saldo: ${nextSenderBalance} coinów.`)
      await loadMessages()
    } catch (error) {
      console.error('live chat tip error', error)
      setStatus('Nie udało się wysłać tipa albo zapisać salda.')
    } finally {
      setTippingId('')
    }
  }

  const addEmoji = (emoji) => {
    setText(prev => `${prev || ''}${emoji}`.trimStart())
    setShowEmojiPicker(false)
  }

  const chatEmojis = ['🔥', '🎯', '💎', '👏', '😂', '😮', '🎉', '🚀', '👀', '🙂', '👍', '❤️']

  return (
    <section className="livechat226-card betai-right-chat-final" id="betaiChatWidget">
      <div className="betai-live-head-final">
        <div className="betai-live-title-wrap-final">
          <span className="livechat226-title-dot"></span>
          <div className="livechat226-kicker">Live Chat</div>
        </div>
      </div>

      <div className="betai-chat-stats-final">
        <div className="livechat226-stat betai-chat-stat-final">
          <span>TOP UŻYTKOWNIK (24H)</span>
          <div className="betai-stat-user-final"><b className="betai-trophy-final">🏆</b><div><strong>{leader?.name || 'Brak lidera'}</strong><small>{leader ? `${leader.count} wiadomości` : `${todayCount} wiadomości dziś`}</small></div></div>
        </div>
        <div className="livechat226-stat betai-chat-stat-final"><span>NAGRODA DNIA</span><strong>🪙 FREE +1 / PREMIUM +2</strong><small>lider czatu o 00:00</small></div>
        <div className="livechat226-stat betai-chat-stat-final"><span>AKTYWNI TERAZ</span><strong>👥 {onlineCount}</strong></div>
      </div>


      <div className="livechat226-messages betai-chat-messages-final" id="liveChatMessages226">
        {messages.length ? messages.map(msg => {
          const msgEmail = normalizeEmail(msg.user_email)
          const name = msg.user_name || nameFromEmail(msgEmail)
          const mine = Boolean(
            (msgEmail && msgEmail === email) ||
            (getProfileUsername(user) && normalizeEmail(name) === getProfileUsername(user))
          )
          const isAdmin = msgEmail === 'smilhytv@gmail.com'
          const isLeader = leader?.email && leader.email === msgEmail
          const avatar = msg.avatar_url || (mine ? currentAvatarUrl : '')
          return (
            <div className={`livechat226-msg ${mine ? 'me' : ''}`} key={msg.id || msg.created_at}>
              <div className={`livechat226-avatar ${avatar ? 'has-avatar' : ''}`}>{avatar ? <img src={avatar} alt="" /> : initialsFromName(name)}</div>
              <div className="livechat226-bubble">
                <div className="livechat226-meta">
                  <span className="livechat226-name">{name}</span>
                  {isAdmin && <span className="livechat226-badge admin">Admin</span>}
                  {isLeader && <span className="livechat226-badge leader">Top aktywność</span>}
                  <span className="livechat226-time">{msg.created_at ? new Date(msg.created_at).toLocaleTimeString('pl-PL', { hour:'2-digit', minute:'2-digit' }) : '--:--'}</span>
                </div>
                <div className="livechat226-text">{msg.message}</div>
                <div className="livechat226-actions">
                  {!mine ? <button className="livechat226-tipbtn" type="button" disabled={tippingId === String(msg.id)} onClick={() => sendTip(msg)}>{tippingId === String(msg.id) ? '...' : '🎁 Tip 1'}</button> : null}
                  <span className="livechat226-tipmeta">Tips: {Number(msg.tipped_amount || 0)}</span>
                </div>
              </div>
            </div>
          )
        }) : <div className="livechat226-empty">Brak wiadomości. Napisz pierwszą wiadomość i uruchom live chat.</div>}
      </div>

      <div className="livechat226-composer betai-composer-final">
        <div className="livechat226-input-wrap betai-input-wrap-final betai-input-actions-final">
          <input className="livechat226-input" maxLength={240} value={text} onChange={e => setText(e.target.value)} onKeyDown={e => { if (e.key === 'Enter') { e.preventDefault(); sendMessage() } }} placeholder="Napisz wiadomość..." />

          <div className="betai-emoji-picker-wrap-final betai-emoji-inline-final">
            <button
              className="betai-emoji-toggle-final"
              type="button"
              onClick={() => setShowEmojiPicker(prev => !prev)}
              aria-expanded={showEmojiPicker}
              aria-label="Pokaż emotki"
              title="Emotki"
            >
              😊
            </button>
            {showEmojiPicker && (
              <div className="betai-emoji-panel-final betai-emoji-panel-inline-final">
                {chatEmojis.map((emoji) => (
                  <button className="livechat226-emoji" key={emoji} type="button" onClick={() => addEmoji(emoji)}>{emoji}</button>
                ))}
              </div>
            )}
          </div>

          <button className="betai-tip-main-final betai-tip-inline-final" type="button" onClick={() => setStatus('Tip możesz wysłać przy wiadomości innego użytkownika.')}>🎁 TIP 1</button>
          <button className="livechat226-send betai-send-final" type="button" onClick={() => sendMessage()} disabled={sending || !text.trim()}>{sending ? '...' : '➤'}</button>
        </div>
        
      </div>    </section>
  )
}




// V1158 — prawa ramka Dashboard: TOP 3 AI typy dnia, tylko mecze przyszłe.
// Nie pokazuje meczów live/zakończonych ani takich, które startują za mniej niż 5 minut.
// Cache jest tylko dla tej ramki Dashboardu i nie dotyka logiki innych zakładek.
const BETAI_RIGHT_DAILY_AI_CACHE_PREFIX_V1156 = 'betai_right_daily_ai_picks_locked_v1609_min65_odds150_'
const BETAI_RIGHT_DAILY_AI_MIN_START_MS_V1158 = 5 * 60 * 1000

function getBetAiWarsawDayKeyV1156(value = new Date()) {
  try {
    const parts = new Intl.DateTimeFormat('en-CA', {
      timeZone: 'Europe/Warsaw',
      year: 'numeric',
      month: '2-digit',
      day: '2-digit'
    }).formatToParts(value)
    const get = type => parts.find(p => p.type === type)?.value || ''
    return `${get('year')}-${get('month')}-${get('day')}`
  } catch (_) {
    return new Date().toISOString().slice(0, 10)
  }
}

function getBetAiNextWarsawDayKeyV1156(dayKey = getBetAiWarsawDayKeyV1156()) {
  const date = new Date(`${dayKey}T12:00:00Z`)
  date.setUTCDate(date.getUTCDate() + 1)
  return getBetAiWarsawDayKeyV1156(date)
}

function isBetAiRightFutureKickoffV1158(value, minMs = BETAI_RIGHT_DAILY_AI_MIN_START_MS_V1158) {
  try {
    const t = value ? new Date(value).getTime() : 0
    if (!t || Number.isNaN(t)) return false
    return t > Date.now() + minMs
  } catch (_) {
    return false
  }
}

function normalizeBetAiRightDailyAiPickV1158(pick = {}, dayKey = getBetAiWarsawDayKeyV1156()) {
  if (!pick || typeof pick !== 'object') return null
  const date = pick.date || pick.event_time || pick.kickoff_time || pick.match_time || ''
  const home = pick.home || pick.team_home || pick.home_team || ''
  const away = pick.away || pick.team_away || pick.away_team || ''
  if (!home || !away || !date) return null
  if (getBetAiRightTipDayKeyV1157(date) !== dayKey) return null
  if (!isBetAiRightFutureKickoffV1158(date)) return null
  return {
    ...pick,
    id: String(pick.id || pick.ai_external_key || `${home}-${away}-${date}`),
    dayKey,
    home,
    away,
    date,
    homeLogo: pick.homeLogo || pick.home_logo || pick.team_home_logo || pick.homeTeamLogo || pick.home_team_logo || pick.fixture_json?.homeLogo || pick.fixture_json?.home_logo || null,
    awayLogo: pick.awayLogo || pick.away_logo || pick.team_away_logo || pick.awayTeamLogo || pick.away_team_logo || pick.fixture_json?.awayLogo || pick.fixture_json?.away_logo || null,
    homeTeamId: pick.homeTeamId || pick.home_team_id || pick.team_home_id || pick.home_id || pick.fixture_json?.homeTeamId || pick.fixture_json?.home_team_id || null,
    awayTeamId: pick.awayTeamId || pick.away_team_id || pick.team_away_id || pick.away_id || pick.fixture_json?.awayTeamId || pick.fixture_json?.away_team_id || null,
    matchName: pick.matchName || pick.match_name || `${home} vs ${away}`,
    league: pick.league || pick.league_name || pick.competition || 'Football',
    market: pick.market || 'Typ AI',
    pick: pick.pick || pick.selection || pick.prediction || 'Najmocniejszy typ AI',
    odds: Number(pick.odds || 1.75).toFixed(2),
    confidence: Math.round(Number(pick.confidence || pick.ai_confidence || pick.ai_score || pick.probability || 68)),
  }
}

const BETAI_RIGHT_DAILY_AI_MIN_CONFIDENCE_V1609 = 65
const BETAI_RIGHT_DAILY_AI_MIN_ODDS_V1609 = 1.50

function passesBetAiRightDailyAiRulesV1609(pick = {}) {
  const odds = Number(pick.odds ?? pick.course ?? pick.kurs ?? 0)
  const confidence = Number(pick.confidence ?? pick.ai_confidence ?? pick.ai_score ?? pick.probability ?? pick.model_probability ?? 0)
  return Number.isFinite(odds) && Number.isFinite(confidence)
    && odds >= BETAI_RIGHT_DAILY_AI_MIN_ODDS_V1609
    && confidence >= BETAI_RIGHT_DAILY_AI_MIN_CONFIDENCE_V1609
}

function filterBetAiRightDailyAiPicksV1158(picks = [], dayKey = getBetAiWarsawDayKeyV1156()) {
  const seen = new Set()
  return (picks || [])
    .map(p => normalizeBetAiRightDailyAiPickV1158(p, dayKey))
    .filter(Boolean)
    .filter(passesBetAiRightDailyAiRulesV1609)
    .filter(pick => {
      const key = String(pick.id || `${pick.home}-${pick.away}-${pick.date}`)
      if (seen.has(key)) return false
      seen.add(key)
      return true
    })
    .sort((a, b) => Number(b.confidence || 0) - Number(a.confidence || 0))
    .slice(0, 3)
}

function readBetAiRightDailyAiCacheV1156(dayKey, lockMode = false) {
  try {
    const keys = [
      `${BETAI_RIGHT_DAILY_AI_CACHE_PREFIX_V1156}${dayKey}`,
      `betai_right_daily_ai_picks_v1162_${dayKey}`,
      `betai_right_daily_ai_picks_v1156_${dayKey}`,
      `betai_right_daily_ai_picks_v1157_${dayKey}`,
      `betai_right_daily_ai_picks_v1158_${dayKey}`,
      `betai_right_daily_ai_picks_v1159_${dayKey}`,
    ]
    for (const key of keys) {
      const raw = localStorage.getItem(key)
      const parsed = raw ? JSON.parse(raw) : null
      if (Array.isArray(parsed?.picks) && parsed.picks.length) {
        const normalized = parsed.picks
          .map(p => normalizeBetAiRightDailyAiPickForCacheV1164(p, dayKey))
          .filter(Boolean)
          .slice(0, 3)
        if (normalized.length) {
          if (key !== `${BETAI_RIGHT_DAILY_AI_CACHE_PREFIX_V1156}${dayKey}`) {
            saveBetAiRightDailyAiCacheV1156(dayKey, normalized)
          }
          // LOCK MODE: jeżeli TOP 3 już zapisane na dzisiejszą datę,
          // nie filtrujemy i nie nadpisujemy ich przy każdym refreshu.
          if (lockMode && filterBetAiRightDailyAiPicksV1158(normalized, dayKey).length >= 3) return filterBetAiRightDailyAiPicksV1158(normalized, dayKey)
          return filterBetAiRightDailyAiPicksV1158(normalized, dayKey)
        }
      }
    }
    return []
  } catch (_) {
    return []
  }
}

function normalizeBetAiRightDailyAiPickForCacheV1164(pick = {}, dayKey = getBetAiWarsawDayKeyV1156()) {
  if (!pick || typeof pick !== 'object') return null
  const date = pick.date || pick.event_time || pick.kickoff_time || pick.match_time || ''
  const home = pick.home || pick.team_home || pick.home_team || ''
  const away = pick.away || pick.team_away || pick.away_team || ''
  if (!home || !away || !date) return null
  if (String(pick.dayKey || dayKey) !== dayKey && getBetAiRightTipDayKeyV1157(date) !== dayKey) return null
  return {
    ...pick,
    id: String(pick.id || pick.ai_external_key || `${home}-${away}-${date}`),
    dayKey,
    home,
    away,
    date,
    homeLogo: pick.homeLogo || pick.home_logo || pick.team_home_logo || pick.homeTeamLogo || pick.home_team_logo || pick.fixture_json?.homeLogo || pick.fixture_json?.home_logo || null,
    awayLogo: pick.awayLogo || pick.away_logo || pick.team_away_logo || pick.awayTeamLogo || pick.away_team_logo || pick.fixture_json?.awayLogo || pick.fixture_json?.away_logo || null,
    homeTeamId: pick.homeTeamId || pick.home_team_id || pick.team_home_id || pick.home_id || pick.fixture_json?.homeTeamId || pick.fixture_json?.home_team_id || null,
    awayTeamId: pick.awayTeamId || pick.away_team_id || pick.team_away_id || pick.away_id || pick.fixture_json?.awayTeamId || pick.fixture_json?.away_team_id || null,
    matchName: pick.matchName || pick.match_name || `${home} vs ${away}`,
    league: pick.league || pick.league_name || pick.competition || 'Football',
    market: pick.market || 'Typ AI',
    pick: pick.pick || pick.selection || pick.prediction || 'Najmocniejszy typ AI',
    odds: Number(pick.odds || 1.75).toFixed(2),
    confidence: Math.round(Number(pick.confidence || pick.ai_confidence || pick.ai_score || pick.probability || 68)),
  }
}

function saveBetAiRightDailyAiCacheV1156(dayKey, picks = []) {
  try {
    localStorage.setItem(`${BETAI_RIGHT_DAILY_AI_CACHE_PREFIX_V1156}${dayKey}`, JSON.stringify({
      dayKey,
      savedAt: new Date().toISOString(),
      locked: true,
      picks: (picks || []).slice(0, 3)
    }))
  } catch (_) {}
}


function getBetAiRightTipDayKeyV1157(value) {
  try {
    const d = value instanceof Date ? value : new Date(value || Date.now())
    if (Number.isNaN(d.getTime())) return ''
    return getBetAiWarsawDayKeyV1156(d)
  } catch (_) {
    return ''
  }
}

function mapBetAiRightSavedTipV1157(row = {}, index = 0, dayKey = getBetAiWarsawDayKeyV1156()) {
  const home = row.team_home || row.home || row.home_team || row.fixture_json?.home || ''
  const away = row.team_away || row.away || row.away_team || row.fixture_json?.away || ''
  if (!home || !away) return null
  const rawDate = row.event_time || row.kickoff_time || row.match_time || row.fixture_date || ''
  return {
    id: String(row.ai_external_key || row.external_fixture_id || row.id || `${home}-${away}-${rawDate}`),
    dayKey,
    matchName: row.match_name || row.match || `${home} vs ${away}`,
    home,
    away,
    homeLogo: row.home_logo || row.homeLogo || row.team_home_logo || row.fixture_json?.homeLogo || row.fixture_json?.home_logo || null,
    awayLogo: row.away_logo || row.awayLogo || row.team_away_logo || row.fixture_json?.awayLogo || row.fixture_json?.away_logo || null,
    homeTeamId: row.home_team_id || row.homeTeamId || row.team_home_id || row.fixture_json?.homeTeamId || row.fixture_json?.home_team_id || null,
    awayTeamId: row.away_team_id || row.awayTeamId || row.team_away_id || row.fixture_json?.awayTeamId || row.fixture_json?.away_team_id || null,
    league: row.league_name || row.league || row.competition || 'Football',
    date: rawDate,
    market: row.market || row.bet_type || 'Typ AI',
    pick: row.selection || row.pick || row.prediction || 'Najmocniejszy typ AI',
    odds: Number(row.odds || 1.75).toFixed(2),
    confidence: Math.round(Number(row.ai_confidence || row.ai_score || row.probability || row.model_probability || 68)),
  }
}

async function loadBetAiRightSavedSupabasePicksV1157(dayKey = getBetAiWarsawDayKeyV1156()) {
  if (!isSupabaseConfigured || !supabase) return []
  try {
    const nextDay = getBetAiNextWarsawDayKeyV1156(dayKey)
    const { data, error } = await supabase
      .from('tips').select('*')
      .or('ai_source.eq.real_ai,ai_source.ilike.%ai%,source.eq.AI,source.ilike.%ai%,source.ilike.%live_ai%')
      .gte('event_time', `${dayKey}T00:00:00`)
      .lt('event_time', `${nextDay}T00:00:00`)
      .order('ai_confidence', { ascending: false, nullsFirst: false })
      .limit(80)
    if (error) throw error
    const seen = new Set()
    return (data || [])
      .map((row, index) => mapBetAiRightSavedTipV1157(row, index, dayKey))
      .filter(Boolean)
      .filter(pick => getBetAiRightTipDayKeyV1157(pick.date || '') === dayKey)
      .filter(pick => isBetAiRightFutureKickoffV1158(pick.date))
      .filter(pick => {
        const key = String(pick.id || `${pick.home}-${pick.away}-${pick.date}`)
        if (seen.has(key)) return false
        seen.add(key)
        return true
      })
      .sort((a, b) => Number(b.confidence || 0) - Number(a.confidence || 0))
      .slice(0, 3)
  } catch (err) {
    console.warn('right daily AI saved tips load skipped:', err?.message || err)
    return []
  }
}

async function triggerBetAiRightDailyGeneratorV1157(dayKey = getBetAiWarsawDayKeyV1156()) {
  const attemptKey = `betai_right_daily_ai_generate_attempt_v1157_${dayKey}`
  try {
    // Jeżeli już próbowaliśmy w tej karcie, nie mielimy endpointu co sekundę.
    const previous = localStorage.getItem(attemptKey)
    if (previous) return { skipped: true }
  } catch (_) {}
  const controller = new AbortController()
  const timer = setTimeout(() => controller.abort(), 18000)
  try {
    const res = await fetch('/.netlify/functions/generate-live-ai-picks?days=1&limit=3', {
      method: 'POST',
      cache: 'no-store',
      signal: controller.signal
    })
    const json = await res.json().catch(() => ({}))
    if (res.ok && Number(json.inserted || 0) > 0) {
      try { localStorage.setItem(attemptKey, JSON.stringify({ at: new Date().toISOString(), inserted: Number(json.inserted || 0) })) } catch (_) {}
    }
    return { ok: res.ok, json }
  } catch (err) {
    return { ok: false, error: err?.message || String(err) }
  } finally {
    clearTimeout(timer)
  }
}

function extractBetAiRightFixturesV1156(payload = {}) {
  const buckets = [payload.fixtures, payload.events, payload.items, payload.data, payload.matches, payload.response, payload.results, payload?.data?.fixtures, payload?.data?.events, payload?.data?.response]
  const out = []
  const push = item => {
    if (!item) return
    if (Array.isArray(item)) return item.forEach(push)
    if (typeof item !== 'object') return
    const fixture = item.fixture || item.event || item.match || item.game || null
    const teams = item.teams || {}
    const league = item.league || item.competition || {}
    const homeObj = teams.home || item.homeTeam || item.home_team || {}
    const awayObj = teams.away || item.awayTeam || item.away_team || {}
    const home = item.home || item.team_home || item.home_team || item.homeTeam || homeObj.name || item.home_name || ''
    const away = item.away || item.team_away || item.away_team || item.awayTeam || awayObj.name || item.away_name || ''
    const date = item.commence_time || item.event_time || item.kickoff_time || item.match_time || item.date || fixture?.date || item.starting_at || ''
    if (!home || !away) return
    out.push({
      ...item,
      id: item.id || item.fixture_id || item.external_fixture_id || fixture?.id || `${home}-${away}-${date}`,
      home,
      away,
      homeLogo: item.homeLogo || item.home_logo || item.team_home_logo || homeObj.logo || homeObj.image || homeObj.logo_url || null,
      awayLogo: item.awayLogo || item.away_logo || item.team_away_logo || awayObj.logo || awayObj.image || awayObj.logo_url || null,
      homeTeamId: item.homeTeamId || item.home_team_id || item.team_home_id || homeObj.id || homeObj.team_id || null,
      awayTeamId: item.awayTeamId || item.away_team_id || item.team_away_id || awayObj.id || awayObj.team_id || null,
      league: item.league_name || item.league || item.competition || league.name || item.country || 'Football',
      date,
      status_short: item.status_short || item.statusShort || fixture?.status?.short || item.status?.short || item.status,
      status_long: item.status_long || item.statusLong || fixture?.status?.long || item.status?.long || item.status_text,
    })
  }
  buckets.forEach(push)
  return out
}

function betAiRightHashV1156(value = '') {
  let h = 0
  const s = String(value || '')
  for (let i = 0; i < s.length; i += 1) h = ((h << 5) - h + s.charCodeAt(i)) | 0
  return Math.abs(h)
}

function isBetAiRightPrematchV1156(match = {}) {
  const short = String(match.status_short || '').toUpperCase()
  const long = String(match.status_long || '').toLowerCase()
  if (['FT','AET','PEN','CANC','ABD','AWD','WO'].includes(short) || long.includes('finished') || long.includes('ended')) return false
  if (['1H','HT','2H','ET','BT','P','SUSP','INT','LIVE'].includes(short) || long.includes('live') || long.includes('progress') || long.includes('half')) return false
  return isBetAiRightFutureKickoffV1158(match.date || match.commence_time || match.event_time || match.kickoff_time || match.match_time)
}

function buildBetAiRightPickV1156(match = {}, index = 0, dayKey = getBetAiWarsawDayKeyV1156()) {
  const home = match.home || 'Gospodarze'
  const away = match.away || 'Goście'
  const league = match.league || 'Football'
  const seed = `${dayKey}-${league}-${home}-${away}-${match.date || ''}`
  const h = betAiRightHashV1156(seed)
  const markets = [
    { market: 'Podwójna szansa', pick: `${home} lub remis`, add: 8 },
    { market: 'Suma goli', pick: 'Powyżej 1.5 gola', add: 10 },
    { market: 'Suma goli', pick: 'Poniżej 3.5 gola', add: 7 },
    { market: 'BTTS', pick: 'Obie strzelą — Tak', add: 4 },
    { market: '1X2', pick: `${home} wygra`, add: 3 },
    { market: '1X2', pick: `${away} wygra`, add: 1 },
  ]
  const selected = markets[h % markets.length]
  const base = 66 + (h % 18) + selected.add
  const confidence = Math.max(61, Math.min(91, base - index * 2))
  const odds = (1.35 + ((Math.floor(h / 11) % 66) / 100)).toFixed(2)
  return {
    id: String(match.id || seed),
    dayKey,
    matchName: `${home} vs ${away}`,
    home,
    away,
    homeLogo: match.homeLogo || match.home_logo || null,
    awayLogo: match.awayLogo || match.away_logo || null,
    homeTeamId: match.homeTeamId || match.home_team_id || null,
    awayTeamId: match.awayTeamId || match.away_team_id || null,
    league,
    date: match.date || '',
    market: selected.market,
    pick: selected.pick,
    odds,
    confidence,
  }
}

function DailyAiPicksRightPanelV1156() {
  const [dayKey, setDayKey] = useState(getBetAiWarsawDayKeyV1156())
  const [picks, setPicks] = useState(() => readBetAiRightDailyAiCacheV1156(getBetAiWarsawDayKeyV1156(), true))
  const [loading, setLoading] = useState(!readBetAiRightDailyAiCacheV1156(getBetAiWarsawDayKeyV1156(), true).length)
  const [notice, setNotice] = useState('')

  useEffect(() => {
    let alive = true
    async function loadDailyPicks() {
      const today = getBetAiWarsawDayKeyV1156()
      setDayKey(today)
      const cached = readBetAiRightDailyAiCacheV1156(today, true)
      if (cached.length >= 3) {
        setPicks(cached.slice(0, 3))
        setLoading(false)
        setNotice(`TOP 3 zapisane na ${today}`)
        return
      }

      setLoading(true)
      setNotice(cached.length ? `Mam ${cached.length}/3 — dobieram kolejne przyszłe mecze...` : 'Sprawdzam zapisane typy AI na dziś: min. 65% i kurs 1.50+...')
      try {
        const savedFromDb = await loadBetAiRightSavedSupabasePicksV1157(today)
        let collected = filterBetAiRightDailyAiPicksV1158([...cached, ...savedFromDb], today)
        if (collected.length >= 3) {
          saveBetAiRightDailyAiCacheV1156(today, collected)
          if (!alive) return
          setPicks(collected.slice(0, 3))
          setNotice(`TOP 3 wczytane z bazy na ${today}`)
          return
        }

        // WERSJA 1480 SAFE: prawy panel nie odpala już automatycznie get-sports-events.
        // Ten widget pokazuje wyłącznie typy zapisane w Supabase/localStorage, żeby dashboard nie dusił API po każdym wejściu.
        if (!alive) return
        setPicks(collected.slice(0, 3))
        setNotice(collected.length ? `Wczytano ${collected.length}/3 zapisane typy AI na dziś.` : 'Brak zapisanych typów AI spełniających warunek 65% i kurs 1.50+. Skan uruchom ręcznie w zakładce Typy AI.')
        return

        if (!alive) return
        setPicks([])
        setNotice('Brak przyszłych meczów na dziś — bez live i zakończonych')
      } finally {
        if (alive) setLoading(false)
      }
    }

    loadDailyPicks()
    const interval = setInterval(() => {
      const nowKey = getBetAiWarsawDayKeyV1156()
      if (nowKey !== dayKey) loadDailyPicks()
    }, 60 * 1000)
    return () => { alive = false; clearInterval(interval) }
  }, [dayKey])

  return (
    <section className="panel ai-day-panel-right ai-day-panel-real-v1156">
      <div className="panel-head"><h2><span className="ai-day-title-accent">AI</span> Typy dnia</h2><a>{dayKey}</a></div>
      {loading && !picks.length ? (
        <div className="empty-mini">Ładowanie TOP 3 przyszłych typów AI na dziś...</div>
      ) : picks.length ? picks.map((pick, index) => (
        <div className="ai-pick ai-pick-real-v1156 ai-pick-real-v1162 ai-pick-real-v1163" key={`${pick.id}-${index}`}>
          <div className="ai-day-pick-body-v1163">
            <div className="ai-day-matchline-v1163">
              <TipTeamLogo logo={pick.homeLogo || pick.home_logo} teamId={pick.homeTeamId || pick.home_team_id} name={pick.home} />
              <b className="ai-day-team-name-v1163 ai-day-home-name-v1164">{pick.home}</b>
              <span className="ai-day-vs-dot-v1162 ai-day-vs-inline-v1163">vs</span>
              <b className="ai-day-team-name-v1163 ai-day-away-name-v1164">{pick.away}</b>
              <TipTeamLogo logo={pick.awayLogo || pick.away_logo} teamId={pick.awayTeamId || pick.away_team_id} name={pick.away} />
            </div>
            <small>{pick.league}</small>
            <small>Typ: {pick.pick} • Kurs: {Number(pick.odds || 0).toFixed(2)}</small>
            <div className="tiny-progress"><i style={{width:`${Math.max(5, Math.min(100, Number(pick.confidence || 0)))}%`}}></i></div>
          </div>
          <strong>{Number(pick.confidence || 0)}%</strong>
        </div>
      )) : (
        <div className="empty-mini">Brak zapisanych typów AI na dziś. Bez meczów live/zakończonych. Spróbuje ponownie po odświeżeniu.</div>
      )}
    </section>
  )
}

