                            {!isOwnComment(comment) && !isAdminUser(user) ? <button type="button" onClick={() => { onToast?.({ type: 'info', title: 'Społeczność', message: 'Komentarz został zgłoszony.' }); setOpenCommentMenuId(null) }}>Zgłoś</button> : null}
