  async function handleForgotPassword() {
    if (!isSupabaseConfigured || !supabase) {
      showMessage('error', t.notConfiguredReset)
      return
    }

    const email = String(form.email || '').trim().toLowerCase()
    if (!email) {
      showMessage('error', t.resetMissingEmail)
      return
    }

    setSubmitting(true)
    showMessage('info', t.resetSending)

    try {
      const redirectTo = typeof window !== 'undefined' ? `${window.location.origin}/?type=recovery` : undefined
      const { error } = await supabase.auth.resetPasswordForEmail(
        email,
        redirectTo ? { redirectTo } : undefined
      )
      if (error) throw error
      showMessage('success', t.resetSuccess)
    } catch (error) {
      showMessage('error', error?.message || t.authFailed)
    } finally {
      setSubmitting(false)
    }
  }

  async function authWithTimeout(promise, timeoutMs = 12000) {
    let timer
    try {
      return await Promise.race([
        promise,
        new Promise((_, reject) => {
          timer = window.setTimeout(() => reject(new Error('Autoryzacja trwa za długo. Spróbuj ponownie za chwilę — Supabase może jeszcze wracać po zmianie dysku.')), timeoutMs)
        })
      ])
    } finally {
      if (timer) window.clearTimeout(timer)
    }
  }

  async function handleSubmit(event) {
    event.preventDefault()
    setAuthMessage('')

    if (!isSupabaseConfigured || !supabase) {
      showMessage('error', t.notConfiguredLogin)
      return
    }

    const email = String(form.email || '').trim().toLowerCase()
    const password = String(form.password || '')

    try {
      if (form.agree) {
        localStorage.setItem('betai_remember_login', '1')
        localStorage.setItem('betai_remember_email', email)
      } else {
        localStorage.removeItem('betai_remember_login')
        localStorage.removeItem('betai_remember_email')
      }
    } catch (_) {}
    const username = String(form.username || '').trim()
    const derivedUsername = username || (email.split('@')[0] || '').replace(/[^a-zA-Z0-9._-]/g, '').slice(0, 24) || `user${Date.now().toString().slice(-6)}`
    const repeatPassword = String(form.repeatPassword || password)

    if (!email) {
      showMessage('error', t.enterEmail)
      return
    }

    if (!password) {
      showMessage('error', t.enterPassword)
      return
    }

    setSubmitting(true)
    showMessage('info', t.authorizing)

    try {
      if (mode === 'register') {
        if (password.length < 8) throw new Error(t.shortPassword)
        if (password !== repeatPassword) throw new Error(t.passwordMismatch)

        const { data, error } = await authWithTimeout(supabase.auth.signUp({
          email,
          password,
          options: {
            data: {
              username: derivedUsername,
              display_name: derivedUsername,
              referral_code: getStoredReferralCode(),
              referralCode: getStoredReferralCode(),
              ref: getStoredReferralCode(),
              r: getStoredReferralCode()
            }
          }
        }))

        if (error) {
          const msg = String(error?.message || '').toLowerCase()
          if (msg.includes('already registered') || msg.includes('already exists') || msg.includes('user already')) {
            throw new Error('Konto z tym adresem email już istnieje. Zaloguj się albo użyj opcji przypomnienia hasła.')
          }
          throw error
        }

        const createdUser = data?.user || data?.session?.user || null
        const identities = Array.isArray(createdUser?.identities) ? createdUser.identities : null
        if (createdUser && identities && identities.length === 0) {
          showMessage('error', 'Konto z tym adresem email już istnieje. Zaloguj się albo użyj opcji przypomnienia hasła.')
          return
        }

        if (data?.session?.user) {
          onAuth?.(data.session.user)
          try {
            const code = getStoredReferralCode()
            if (code && isSupabaseConfigured && supabase) {
              await supabase.rpc('register_referral_signup', {
                p_referred_id: data.session.user.id,
                p_referral_code: code,
                p_referred_email: normalizeEmail(data.session.user.email || email)
              })
              try { localStorage.removeItem('betai_referral_code') } catch (_) {}
            }
          } catch (referralError) {
            console.warn('referral signup frontend retry skipped', referralError)
          }
          showMessage('success', t.accountCreatedLogged)
        } else {
          showMessage('success', t.accountCreatedConfirm)
        }
      } else {
        const { data, error } = await authWithTimeout(supabase.auth.signInWithPassword({
          email,
          password
        }))

        if (error) throw error
        if (data?.user) {
          onAuth?.(data.user)
          showMessage('success', t.loginSuccess)
        }
      }
    } catch (error) {
      const errorText = String(error?.message || '')
      showMessage('error', errorText.includes('Database error saving new user')
        ? t.dbError
        : errorText.toLowerCase().includes('email rate limit')
          ? t.emailLimit
          : (error?.message || t.authFailed))
    } finally {
      setSubmitting(false)
    }
  }

