function BetaiLanguageSwitch({ lang, onChange, compact = false, floating = false, ariaLabel = 'Language switcher' }) {
  const [open, setOpen] = useState(false)
  const currentLang = BETAI_LANGUAGES.includes(lang) ? lang : 'pl'
  const chooseLanguage = (code) => {
    onChange?.(code)
    setOpen(false)
  }

  return (
    <div
      className={`betai-language-switch betai-language-dropdown ${compact ? 'compact' : ''} ${floating ? 'floating' : ''} ${open ? 'is-open' : ''}`}
      aria-label={ariaLabel}
      onBlur={(event) => {
        if (!event.currentTarget.contains(event.relatedTarget)) setOpen(false)
      }}
    >
      <button
        type="button"
        className="betai-language-current is-active"
        onClick={() => setOpen(prev => !prev)}
        aria-haspopup="listbox"
        aria-expanded={open}
        aria-label={`${ariaLabel}: ${BETAI_LANG_NAMES?.[currentLang] || BETAI_LANG_LABELS[currentLang]}`}
        title={BETAI_LANG_NAMES?.[currentLang] || BETAI_LANG_LABELS[currentLang]}
      >
        <span className={`betai-language-flag betai-flag-${currentLang}`} aria-hidden="true" />
        <span className="betai-language-chevron" aria-hidden="true">⌄</span>
      </button>

      {open ? (
        <div className="betai-language-menu" role="listbox">
          {BETAI_LANGUAGES.map(code => (
            <button
              type="button"
              key={code}
              className={currentLang === code ? 'is-active' : ''}
              onClick={() => chooseLanguage(code)}
              role="option"
              aria-selected={currentLang === code}
              aria-label={BETAI_LANG_NAMES?.[code] || BETAI_LANG_LABELS[code]}
              title={BETAI_LANG_NAMES?.[code] || BETAI_LANG_LABELS[code]}
            >
              <span className={`betai-language-flag betai-flag-${code}`} aria-hidden="true" />
              <span className="betai-language-name">{BETAI_LANG_NAMES?.[code] || BETAI_LANG_LABELS[code]}</span>
            </button>
          ))}
        </div>
      ) : null}
    </div>
  )
}

function getFollowStorageKey(userId) {
  return `betai_following_tipsters_${String(userId || 'guest')}`
}

function readLocalFollowingTipsters(userId) {
  if (typeof window === 'undefined' || !userId) return new Set()
  try {
    const raw = window.localStorage.getItem(getFollowStorageKey(userId))
    const parsed = raw ? JSON.parse(raw) : []
    return new Set(Array.isArray(parsed) ? parsed.map(value => String(value).toLowerCase()).filter(Boolean) : [])
  } catch (_) {
    return new Set()
  }
}

function writeLocalFollowingTipsters(userId, values) {
  if (typeof window === 'undefined' || !userId) return
  try {
    const list = [...(values || [])].map(value => String(value).toLowerCase()).filter(Boolean)
    window.localStorage.setItem(getFollowStorageKey(userId), JSON.stringify([...new Set(list)]))
  } catch (_) {}
}

function addLocalFollowingTipster(userId, keys = []) {
  const current = readLocalFollowingTipsters(userId)
  keys.map(value => String(value || '').toLowerCase()).filter(Boolean).forEach(key => current.add(key))
  writeLocalFollowingTipsters(userId, current)
  return current
}

function removeLocalFollowingTipster(userId, keys = []) {
  const current = readLocalFollowingTipsters(userId)
  keys.map(value => String(value || '').toLowerCase()).filter(Boolean).forEach(key => current.delete(key))
  writeLocalFollowingTipsters(userId, current)
  return current
}

function mergeFollowingSets(...sets) {
  const merged = new Set()
  sets.forEach(setLike => {
    ;[...(setLike || [])].forEach(value => {
      const clean = String(value || '').toLowerCase()
      if (clean) merged.add(clean)
    })
  })
  return merged
}


function parseBetaiKickoffTime(value) {
  if (value === null || value === undefined) return NaN
  const raw = String(value || '').trim()
  if (!raw) return NaN

  const iso = Date.parse(raw)
  if (Number.isFinite(iso)) return iso

  const polish = raw.match(/(\d{1,2})[.\/-](\d{1,2})(?:[.\/-](\d{2,4}))?[^0-9]*(\d{1,2})[:.](\d{2})/)
  if (polish) {
    const day = Number(polish[1])
    const month = Number(polish[2])
    let year = polish[3] ? Number(polish[3]) : new Date().getFullYear()
    if (year < 100) year += 2000
    const hour = Number(polish[4])
    const minute = Number(polish[5])
    const ts = new Date(year, month - 1, day, hour, minute, 0, 0).getTime()
    return Number.isFinite(ts) ? ts : NaN
  }

  return NaN
}

function getTipKickoffTimestamp(tip = {}) {
  // Najpierw obsługa najczęstszego zapisu z Supabase: match_date='YYYY-MM-DD' + match_time='HH:mm'.
  // Wcześniej sam match_time='02:00' nie dawał daty, więc typ mógł wisieć na Dashboardzie po starcie meczu.
  const dateOnly = String(tip.match_date || tip.fixture_date_day || tip.event_date || '').trim().slice(0, 10)
  const timeOnlyRaw = String(tip.match_time_hhmm || tip.kickoff_time_hhmm || tip.start_time_hhmm || '').trim()
  const timeFromMatchTime = String(tip.match_time || '').trim()
  const timeOnly = timeOnlyRaw || (/^\d{1,2}:\d{2}(?::\d{2})?$/.test(timeFromMatchTime) ? timeFromMatchTime : '')

  if (/^\d{4}-\d{2}-\d{2}$/.test(dateOnly) && /^\d{1,2}:\d{2}(?::\d{2})?$/.test(timeOnly)) {
    const [hour = '00', minute = '00', second = '00'] = timeOnly.split(':')
    const combinedLocal = `${dateOnly}T${String(hour).padStart(2, '0')}:${String(minute).padStart(2, '0')}:${String(second || '00').padStart(2, '0')}`
    const combinedTs = new Date(combinedLocal).getTime()
    if (Number.isFinite(combinedTs)) return combinedTs
  }

  const candidates = [
    tip.event_start_at,
    tip.starts_at,
    tip.start_at,
    tip.match_time,
    tip.event_time,
    tip.kickoff_time,
    tip.start_time,
    tip.fixture_date,
    tip.date_time,
    tip.date
  ]
  for (const value of candidates) {
    const ts = parseBetaiKickoffTime(value)
    if (Number.isFinite(ts)) return ts
  }
  return NaN
}

function isTipAlreadyStarted(tip = {}, now = Date.now()) {
  const fixtureStatus = String(tip.fixture_status || tip.status_short || tip.api_status || '').trim().toUpperCase()
  if (['1H', 'HT', '2H', 'ET', 'BT', 'P', 'SUSP', 'INT', 'FT', 'AET', 'PEN'].includes(fixtureStatus)) return true

  const ts = getTipKickoffTimestamp(tip)
  if (!Number.isFinite(ts)) return false

  // Dashboard i marketplace nie mogą pokazywać/sprzedawać kuponu od minuty rozpoczęcia meczu.
  // Czyli dokładnie od startu: 02:00 znika o 02:00, nie dopiero po rozliczeniu.
  return ts <= now
}

function isTipVisibleInActiveFeed(tip, now = Date.now()) {
  const normalized = normalizeTipRow(tip || {})
  const status = String(normalized.status || 'pending').toLowerCase()
  const approvalStatus = String(normalized.admin_approval_status || normalized.manual_settlement_status || '').toLowerCase()
  const result = String(normalized.result || normalized.manual_settlement_result || normalized.admin_approved_result || '').toLowerCase()

  const settledStatuses = new Set([
    'won', 'win', 'wygrany', 'wygrana',
    'lost', 'loss', 'przegrany', 'przegrana',
    'void', 'push', 'zwrot',
    'cancelled', 'canceled', 'anulowany',
    'rejected'
  ])

  // Świeżo dodany typ ręczny ma być widoczny od razu na dashboardzie.
  // Admin wchodzi dopiero przy ROZLICZENIU ręcznym, czyli kiedy istnieje zgłoszony wynik
  // albo znacznik ręcznej prośby o zatwierdzenie. Samo admin_approval_status='pending'
  // bywa domyślną wartością w przywróconej bazie i nie może ukrywać nowego typu.
  const hasManualSettlementRequest = Boolean(
    normalized.manual_settlement_requested_at ||
    normalized.admin_approved_result ||
    normalized.manual_settlement_result ||
    ['manual_user', 'manual_admin_approved', 'manual_admin_rejected'].includes(String(normalized.settlement_source || '').toLowerCase())
  )
  if ((approvalStatus === 'pending' || approvalStatus === 'pending_admin') && hasManualSettlementRequest) return false
  if (settledStatuses.has(status)) return false
  if (settledStatuses.has(result)) return false

  // v1102: kupon po starcie meczu znika z Dashboardu/marketplace, nawet jeżeli auto-rozliczenie
  // jeszcze nie zdążyło zmienić pending -> won/lost. Zostaje w profilu/Wynikach/Historii.
  if (isTipAlreadyStarted(normalized, now)) return false

  return true
}

