  async function fetchAdminPayoutRequests() {
    if (!userProfile?.isAdmin || !isSupabaseConfigured || !supabase) {
      setAdminPayoutRequests([])
      return
    }

    try {
      const { data, error } = await supabase.rpc('get_admin_payout_requests')

      if (error) {
        console.warn('get_admin_payout_requests RPC error, falling back to table', error)
        throw error
      }

      const rows = Array.isArray(data) ? data : []
      setAdminPayoutRequests(rows.map(row => ({
        ...row,
        display_user: row.display_user || row.user_username || row.username || row.user_email || row.email || row.user_id || '—',
        username: row.user_username || row.username || null,
        display_name: row.user_display_name || row.display_name || row.user_full_name || null,
        user_email: row.user_email_resolved || row.user_email || row.email || null,
        raw_user_id: row.raw_user_id || row.user_id || null
      })))
      return
    } catch (_) {
      // Fallback dla starszej bazy bez RPC
    }

    const { data, error } = await supabase
      .from('payout_requests')
      .select('*')
      .order('created_at', { ascending: false })

    if (error) {
      console.error('fetchAdminPayoutRequests error', error)
      setAdminPayoutRequests([])
      return
    }

    const rows = Array.isArray(data) ? data : []
    const userIds = [...new Set(rows.map(row => row?.user_id).filter(Boolean))]
    let usersById = {}

    if (userIds.length) {
      try {
        const { data: users } = await supabase
          .from('profiles').select('*')
          .in('id', userIds)

        usersById = Object.fromEntries((users || []).map(profile => [
          String(profile.id),
          profile
        ]))
      } catch (profileError) {
        console.warn('fetchAdminPayoutRequests usernames resolve error', profileError)
      }
    }

    setAdminPayoutRequests(rows.map(row => {
      const profile = usersById[String(row?.user_id || '')]
      const displayUser = profile?.username || profile?.display_name || profile?.full_name || profile?.email || row?.user_email || row?.email || row?.user_id || '—'

      return {
        ...row,
        username: profile?.username || row?.username || null,
        display_name: profile?.display_name || profile?.full_name || null,
        user_email: profile?.email || row?.user_email || row?.email || null,
        display_user: displayUser,
        raw_user_id: row?.user_id || null
      }
    }))
  }



  async function getAdminBearerHeaders(extraHeaders = {}) {
    const headers = { ...extraHeaders }
    try {
      const { data } = await supabase.auth.getSession()
      const token = data?.session?.access_token
      if (token) headers.Authorization = `Bearer ${token}`
    } catch (_) {}
    return headers
  }

  async function runPayoutCron() {
    if (!sessionUser?.id || !isAdminUser(sessionUser)) {
      showToast({ type: 'error', title: 'Brak uprawnień', message: 'Tylko admin może uruchomić cron wypłat.' })
      return
    }

    try {
      showToast({ type: 'info', title: 'Cron wypłat', message: 'Uruchamiam testowe przetwarzanie pending wypłat...' })
      const response = await fetch('/.netlify/functions/process-payouts', {
        method: 'POST',
        headers: await getAdminBearerHeaders({ 'Content-Type': 'application/json' })
      })
      const data = await response.json().catch(() => ({}))

      if (!response.ok) {
        throw new Error(data.error || 'Nie udało się uruchomić cron wypłat.')
      }

      showToast({
        type: 'success',
        title: 'Cron zakończony',
        message: `Przetworzono: ${data.processed || 0}. Sprawdź statusy i transfer ID.`
      })

      await fetchAdminPayoutRequests()
      await fetchAdminFinanceReport()
      if (sessionUser?.id) {
        await fetchPayoutRequests(sessionUser.id)
        await fetchTipsterEarnings(sessionUser.id)
        await fetchWalletBalance(sessionUser.id)
      }
    } catch (error) {
      showToast({ type: 'error', title: 'Błąd cron wypłat', message: formatAppErrorMessage(error.message) })
    }
  }

  async function updatePayoutStatus(requestId, status) {
    if (!sessionUser?.id || !isAdminUser(sessionUser)) {
      showToast({ type: 'error', title: 'Brak uprawnień', message: 'Tylko admin może zmieniać status wypłat.' })
      return
    }

    try {
      if (status !== 'rejected') {
        const response = await fetch('/.netlify/functions/approve-payout', {
          method: 'POST',
          headers: await getAdminBearerHeaders({ 'Content-Type': 'application/json' }),
          body: JSON.stringify({ request_id: requestId, admin_user_id: sessionUser.id })
        })

        const data = await response.json().catch(() => ({}))

        if (!response.ok) {
          throw new Error(data.error || 'Nie udało się wykonać realnej wypłaty Stripe Connect.')
        }
      } else {
        const { error } = await supabase.rpc('reject_tipster_payout', { p_request_id: requestId })

        if (error) {
          showToast({ type: 'error', title: 'Błąd aktualizacji', message: formatAppErrorMessage(error.message) })
          return
        }
      }

      showToast({
        type: 'success',
        title: 'Status zmieniony',
        message: status === 'rejected' ? 'Wypłata odrzucona.' : 'Wypłata zatwierdzona i oznaczona jako wypłacona.'
      })

      await fetchAdminPayoutRequests()
      await fetchAdminFinanceReport()
      if (sessionUser?.id) {
        await fetchPayoutRequests(sessionUser.id)
        await fetchTipsterEarnings(sessionUser.id)
        await fetchWalletBalance(sessionUser.id)
      }
    } catch (error) {
      showToast({ type: 'error', title: 'Błąd aktualizacji', message: formatAppErrorMessage(error.message) })
    }
  }





